func newNovelCompareCmd(flags *rootFlags) *cobra.Command {
	var top int
	cmd := &cobra.Command{
		Use:   "compare <st1> <st2>",
		Short: "Compare two states by offbeat-attraction count and surface a few top picks from each.",
		Long: strings.Trim(`
Compare two US states or Canadian provinces by their offbeat-attraction count,
with a few top picks from each. States are fetched live (cached on read); pass
--data-source local to compare only what is already cached.`, "\n"),
		Example: strings.Trim(`
  roadside-america-pp-cli compare TX CA
  roadside-america-pp-cli compare TX CA --top 3 --json`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true", "pp:happy-args": "st1=TX;st2=CA"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 && cmd.Flags().NFlag() == 0 {
				return cmd.Help()
			}
			if len(args) < 2 {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("two state/province codes are required, e.g. compare TX CA"))
			}
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), "would compare two states")
				return nil
			}
			if top <= 0 {
				top = 5
			}
			codes := []string{strings.ToUpper(strings.TrimSpace(args[0])), strings.ToUpper(strings.TrimSpace(args[1]))}
			for _, c := range codes {
				if !roadside.ValidState(c) {
					return usageErr(fmt.Errorf("unknown state/province %q; expected one of: %s", c, roadside.StateCodes()))
				}
			}

			ctx := cmd.Context()
			s, err := openRoadsideStore(ctx)
			if err != nil {
				return err
			}
			defer s.Close()

			view := compareView{Source: roadside.SourceLabel}
			for _, code := range codes {
				atts, _, perr := poolForState(ctx, flags, s, code)
				if perr != nil {
					return perr
				}
				sc := stateCompare{Code: code, Name: roadside.StateName(code), Count: len(atts), Top: []roadside.Attraction{}}
				for i := 0; i < len(atts) && i < top; i++ {
					sc.Top = append(sc.Top, atts[i])
				}
				view.States = append(view.States, sc)
			}
			switch {
			case view.States[0].Count > view.States[1].Count:
				view.Winner = view.States[0].Code
			case view.States[1].Count > view.States[0].Count:
				view.Winner = view.States[1].Code
			default:
				view.Winner = "tie"
			}

			if machineOutput(cmd, flags) {
				return flags.printJSON(cmd, view)
			}
			w := cmd.OutOrStdout()
			for _, sc := range view.States {
				fmt.Fprintf(w, "%s — %d attractions\n", bold(fmt.Sprintf("%s (%s)", sc.Name, sc.Code)), sc.Count)
				for _, a := range sc.Top {
					loc := a.City
					if a.State != "" {
						loc = strings.TrimPrefix(loc+", "+a.State, ", ")
					}
					fmt.Fprintf(w, "  • %s — %s\n", a.Name, loc)
				}
				fmt.Fprintln(w)
			}
			if view.Winner == "tie" {
				fmt.Fprintf(w, "It's a tie at %d each.\n", view.States[0].Count)
			} else {
				fmt.Fprintf(w, "%s has more offbeat attractions.\n", view.Winner)
			}
			fmt.Fprintf(w, "(%s)\n", roadside.SourceLabel)
			return nil
		},
	}
	cmd.Flags().IntVar(&top, "top", 5, "Number of top picks to show per state")
	return cmd
}
